#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        int a, b, c, d, e, f, g, h;
        scanf("%d %d %d %d %d %d %d %d", &a, &b, &c, &d, &e, &f, &g, &h);
        double max_time = -1;
        double max_hour = -1;
        for (int i = a; i <= c; i++) {
            for (int j = 0; j < X * Y; j++) {
                double hour = i + (double)j / (X * Y);
                double minute = (double)j;
                double swapped_hour = minute / (X * Y);
                double swapped_minute = hour * (X * Y);
                if (swapped_hour >= e && swapped_hour <= g && swapped_minute >= f && swapped_minute <= h) {
                    if (hour > max_hour) {
                        max_hour = hour;
                        max_time = minute;
                    }
                }
            }
        }
        if (max_time == -1) {
            printf("-1\n");
        } else {
            printf("%.0f:%.2f\n", max_hour, fmod(max_time, 1) * 60);
        }
    }
    return 0;
}

