const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [X, Y] = readline().split(' ').map(Number);
    const [a, b, c, d, e, f, g, h] = readline().split(' ').map(Number);
    let max_time = -1;
    let max_hour = -1;
    for (let j = a; j <= c; j++) {
        for (let k = 0; k < X * Y; k++) {
            const hour = j + k / (X * Y);
            const minute = k;
            const swapped_hour = minute / (X * Y);
            const swapped_minute = hour * (X * Y);
            if (swapped_hour >= e && swapped_hour <= g && swapped_minute >= f && swapped_minute <= h) {
                if (hour > max_hour) {
                    max_hour = hour;
                    max_time = minute;
                }
            }
        }
    }
    if (max_time === -1) {
        console.log(-1);
